**AsyncLocalStorage là gì?**
- Store data có thể access trong async call stack
- Không cần pass context qua tất cả functions
- Perfect cho request IDs, user context, tracing

**Basic Usage**:
```ts
import { AsyncLocalStorage } from 'async_hooks';

interface RequestContext {
  requestId: string;
  userId?: string;
}

const asyncLocalStorage = new AsyncLocalStorage<RequestContext>();

// Middleware
app.use((req, res, next) => {
  const context: RequestContext = {
    requestId: crypto.randomUUID(),
    userId: req.user?.id,
  };

  asyncLocalStorage.run(context, () => next());
});

// Access anywhere in request
function getRequestId(): string | undefined {
  return asyncLocalStorage.getStore()?.requestId;
}
```

**NestJS Implementation**:
```ts
import { AsyncLocalStorage } from 'async_hooks';

@Injectable()
export class RequestContextService {
  private static storage = new AsyncLocalStorage<Map<string, any>>();

  static run(callback: () => void) {
    this.storage.run(new Map(), callback);
  }

  static set(key: string, value: any) {
    this.storage.getStore()?.set(key, value);
  }

  static get<T>(key: string): T | undefined {
    return this.storage.getStore()?.get(key);
  }
}

// Middleware
@Injectable()
export class RequestContextMiddleware implements NestMiddleware {
  use(req: Request, res: Response, next: NextFunction) {
    RequestContextService.run(() => {
      RequestContextService.set('requestId', crypto.randomUUID());
      next();
    });
  }
}
```

