**Redis Queue (BullMQ)**:
```ts
import { Queue, Worker } from 'bullmq';

// Producer
const emailQueue = new Queue('email', {
  connection: { host: 'redis', port: 6379 },
});

await emailQueue.add('send-welcome', {
  to: 'user@example.com',
  template: 'welcome',
}, {
  attempts: 3,
  backoff: { type: 'exponential', delay: 1000 },
  delay: 5000, // Delayed job
  priority: 1, // Higher = lower priority
});

// Worker
const worker = new Worker('email', async (job) => {
  await sendEmail(job.data);
}, {
  connection: { host: 'redis', port: 6379 },
  concurrency: 5,
});

worker.on('completed', (job) => console.log(`Job ${job.id} completed`));
worker.on('failed', (job, err) => console.error(`Job ${job.id} failed`, err));
```

**Reliability Patterns**:

1. **Idempotency**:
```ts
async function processPayment(job) {
  const { orderId, amount } = job.data;

  // Check if already processed
  const existing = await db.payments.findOne({ orderId });
  if (existing) return existing;

  // Process and record
  const payment = await processAndSave(orderId, amount);
  return payment;
}
```

2. **Dead Letter Queue**:
```ts
const worker = new Worker('email', processor, {
  settings: {
    maxStalledCount: 3,
  },
});

worker.on('failed', async (job, err) => {
  if (job.attemptsMade >= job.opts.attempts) {
    await deadLetterQueue.add('failed-email', {
      originalJob: job.data,
      error: err.message,
    });
  }
});
```

3. **Graceful Shutdown**:
```ts
process.on('SIGTERM', async () => {
  await worker.close();
  process.exit(0);
});
```

