```ts
import * as fc from 'fast-check';

// Property: reverse twice = original
test('reverse is involutory', () => {
  fc.assert(
    fc.property(fc.array(fc.integer()), (arr) => {
      const reversed = [...arr].reverse().reverse();
      return JSON.stringify(reversed) === JSON.stringify(arr);
    })
  );
});

// Property: sort is idempotent
test('sort is idempotent', () => {
  fc.assert(
    fc.property(fc.array(fc.integer()), (arr) => {
      const sorted1 = [...arr].sort((a, b) => a - b);
      const sorted2 = [...sorted1].sort((a, b) => a - b);
      return JSON.stringify(sorted1) === JSON.stringify(sorted2);
    })
  );
});
```

